from abc import ABC, abstractmethodclass ICoveragePyEbyeAggregator(ABC):	"""		Rappresenta un aggregatore di dati di statement coverage, prodotti tramite coverage.py,		in dati corrispondenti alla metrica di entity-level statement coverage.				Viene prodotto un file JSON e il formato in cui vengono restituiti i dati aggregati è il seguente:						- Una lista di dizionari JSON dove ognuno contiene:							* "module" (str): Il nome del modulo, specificato in "dotted path" a partire dalla Focal Project Root Path, a cui appartiene l' entità autonoma di cui è valutata la percentuale di coverage				* "class" (str): L' eventuale nome della classe a cui appartiene l' entità autonoma. Se l' entità è una funzione questo campo è una stringa vuota				* "entity" (str): Il nome dell' entità autonoma di codice di cui è valutata la percentuale di coverage				* "coverage" (float): La percentuale di coverage misurata, come `float` tra 0 e 1 compresi, per l' entità autonoma specificata						Il formato del report di "coverage.py" trattato è specificato dai discendenti di questa interfaccia.	"""			@abstractmethod	def add_exclusion(self, excl_entity: str, pass_onerror: bool=False):		"""			Aggiunge l' entità autonoma specificata tra le entità escluse			per le successive aggregazioni di dati						Parameters			----------				excl_entity: str					Una stringa contenente il nome fully-qualified dell' entità autonoma					da escludere in questo aggregatore.					Il nome è formattato come segue:						`<dotted_module_path>.[<dollarsep_class_path>$]<entity_name>`					in cui:						- [...] rappresenta qualcosa di opzionale						- `<dollarsep_class_path>` è l' eventuale percorso di classi che contiene l' entità `<entity_name>`						- `<entity_name>` è il nome dell' entità autonoma										pass_onerror: bool					Opzionale. Default = `False`. Un booleano che indica se bisogna ignorare					un eventuale errore legato all' esclusione già effettuata dell' entità autonoma					fornita								Raises			------				ValueError					Si verifica se:											- Il parametro `excl_entity` ha valore `None` o è una stringa vuota						- Se il parametro `pass_onerror=False` e il parametro `excl_entity` rappresenta un entità che è già stata esclusa in questo aggregatore		"""		pass			@abstractmethod	def rem_exclusion(self, excl_entity: str, pass_onerror: bool=False):		"""			Rimuove l' entità autonoma specificata di cui era stata richiesta			l' esclusione precedentemente						Parameters			----------				excl_entity: str					Una stringa contenente il nome fully-qualified dell' entità autonoma precedentemente					esclusa da questo aggregatore.					Il nome è formattato come segue:						`<dotted_module_path>.[<dollarsep_class_path>$]<entity_name>`					in cui:						- [...] rappresenta qualcosa di opzionale						- `<dollarsep_class_path>` è l' eventuale percorso di classi che contiene l' entità `<entity_name>`						- `<entity_name>` è il nome dell' entità autonoma										pass_onerror: bool					Opzionale. Default = `False`. Un booleano che indica se bisogna ignorare					un eventuale errore legato all' esclusione mai effettuata dell' entità autonoma					fornita						Raises			------				ValueError					Si verifica se:											- Il parametro `excl_entity` ha valore `None` o è una stringa vuota						- Se il parametro `pass_onerror=False` e il parametro `excl_entity` rappresenta un entità che non è mai stata esclusa in questo aggregatore		"""		pass			@abstractmethod	def aggregate(			self,	        report_path: str,			focal_root: str,			aggr_path: str,	):		"""			Aggrega i dati di statement coverage memorizzati nel report alla path data,			trasformandoli in dati di entity-level statement coverage in base alle entità autonome			di codice (funzioni o metodi) definite nei module-files all' interno della			Focal Project Root Path fornita.			Vengono tralasciate eventuali entità autonome selezionate per l' esclusione			precedentemente alla chiamata di questa operazione.						Al termine dell' aggregazione i dati vengono scritti, nel formato descritto			nel contratto d' interfaccia, all' interno del file alla path `aggr_path`						Parameters			----------				report_path: str					Una stringa rappresentante la path che contiene il report di coverage.py					da utilizzare									focal_root: str					Una stringa rappresentante la Focal Project Root Path legata al report					fornito in cui si trovano le funzioni in base a cui aggregare i dati									aggr_path: str					Una stringa rappresentante la path che conterrà i dati aggregati nel formato					descritto nel contratto d' interfaccia								Raises			------				ValueError					Si verifica se:						- Il parametro `report_path` ha valore `None` oppure è una stringa vuota						- Il parametro `focal_root` ha valore `None` oppure è una stringa vuota						- Il parametro `aggr_path` ha valore `None` oppure è una stringa vuota						- Il parametro `focal_root` rappresenta una path inesistente o inaccessibile						- Il parametro `aggr_path` rappresenta una path inesistente o inaccessibile										WrongReportTypeError					Si verifica se `report_path` rappresenta un report di una tipologia					non trattata dai discendenti di questa interfaccia		"""		pass